sql:
SELECT COUNT(conversion_id) AS total_successful_conversions
FROM conversion_history
WHERE success = 1;

SELECT user_id, MAX(batch_date) AS most_recent_batch_date
FROM batch_conversions
GROUP BY user_id;

SELECT decimal_value, COUNT(*) AS occurrence_count
FROM numbers
GROUP BY decimal_value;

SELECT 
    (SELECT COUNT(*) FROM conversion_history WHERE user_id = 1 AND success = 1) AS successful_conversions,
    (SELECT COUNT(*) FROM conversion_history WHERE user_id = 1 AND success = 0) AS failed_conversions;

SELECT conversion_date, success
FROM conversion_history
ORDER BY conversion_date DESC;

SELECT number_id, decimal_value, hex_value, octal_value
FROM numbers
ORDER BY number_id ASC;
